import { useParams } from 'react-router-dom'
import { defaultLang } from '../i18n/translations'
import { useEffect } from 'react'
import { useTranslation } from '../i18n/useTranslation'
import { SeoHead } from '../components/SeoHead'
import { resolvePlaceholderMeta } from '../config/corporateMenuContent'
import './HomePage.css'
import './SectionPlaceholderPage.css'

/**
 * Placeholder routes for corporate sections (content via CMS on other routes or later).
 */
export default function SectionPlaceholderPage({ sectionKey }) {
  const { slug } = useParams()
  const lang = defaultLang
  const t = useTranslation(lang)
  const { title, description } = resolvePlaceholderMeta(lang, sectionKey, slug)

  useEffect(() => {
    document.documentElement.lang = lang
  }, [lang])

  return (
    <div className="section-placeholder cms-main">
      <SeoHead title={title} description={description} />
      <article className="section-placeholder-article">
        <h1 className="section-placeholder-title">{title}</h1>
        {description ? <p className="section-placeholder-lead">{description}</p> : null}
      </article>
    </div>
  )
}
